1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === QUOTE: Base premiums ===
6	  it("empty item list returns premium of 5 G (processing fee only)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote" as const, items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("single sword returns premium of 115 G (100 base + 10 first insurance + 5 fee)");
14	  it.todo("single amulet returns premium of 71 G (60 base + 6 first + 5 fee)");
15	  it.todo("single staff returns premium of 93 G (80 base + 8 first + 5 fee)");
16	  it.todo("single potion returns premium of 49 G (40 base + 4 first + 5 fee)");
17	  it.todo("single rune component returns premium of 33 G (25 base + 2.5 first rounded up to 3 + 5 fee)");
18	  it.todo("two runes returns premium of 61 G (50 base + 5 first + 5 fee, rounded up)");
19	
20	  // === QUOTE: Component block pricing ===
21	  it.todo("3 alike runes returns block premium (60 base + 6 first + 5 fee = 71 G)");
22	  it.todo("4 runes returns non-block premium (100 base + 10 first + 5 fee = 115 G)");
23	  it.todo("2 runes + 1 moonstone returns 75 base (no block, different types)");
24	  it.todo("3 runes + 3 moonstones returns 120 base (two separate blocks)");
25	
26	  // === QUOTE: Item-specific modifiers ===
27	  it.todo("cursed sword adds 50% surcharge to sword base premium");
28	  it.todo("highly enchanted sword (enchantment >= 5) adds 30% surcharge to sword base premium");
29	  it.todo("cursed and highly enchanted sword has both surcharges applied");
30	  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
31	
32	  // === QUOTE: Policy-wide modifiers ===
33	  it.todo("long-standing customer (>= 2 years) receives 20% loyalty discount on policy base");
34	  it.todo("customer with exactly 2 years qualifies for loyalty discount");
35	  it.todo("follow-up contract (second quote) receives 15% discount on policy base");
36	
37	  // === QUOTE: Multi-item policies ===
38	  it.todo("policy with cursed sword and plain amulet applies curse surcharge only to sword");
39	  it.todo("policy with multiple items sums item base premiums before policy-wide modifiers");
40	
41	  // === QUOTE: Integration - modifier stacking ===
42	  it.todo("newcomer with cursed sword: 100 + 50 curse + 10 first + 5 fee = 165 G");
43	  it.todo("long-standing customer second contract cursed enchanted sword: 155 + 5 fee = 160 G");
44	
45	  // === QUOTE: Rounding ===
46	  it.todo("premium rounds up (in MHPCO's favor) to whole G");
47	
48	  // === CLAIM: Basic payout ===
49	  it.todo("regular sword damage 500 G returns payout 400 G (full reimbursement minus 100 deductible)");
50	  it.todo("component damage 200 G returns payout 100 G (full minus 100 deductible)");
51	
52	  // === CLAIM: Special clauses ===
53	  it.todo("enchantment >= 8 reimburses at 50% of damage then deductible");
54	  it.todo("dragon material fully reimburses then deductible");
55	  it.todo("dragon material with enchantment >= 8: 50% wins then deductible");
56	  it.todo("dragon material with enchantment < 8: full reimbursement then deductible");
57	
58	  // === CLAIM: Cap ===
59	  it.todo("policy cap is 2x insurance sum");
60	  it.todo("successive claims exhaust cap: second claim reduced to remaining cap");
61	
62	  // === CLAIM: Multiple items in one event ===
63	  it.todo("multiple damaged items each have their own deductible");
64	
65	  // === CLAIM: Validation ===
66	  it.todo("damage to item not in policy rejects the claim");
67	  it.todo("more damage entries of a type than policy covers rejects the claim");
68	  it.todo("negative damage amount rejects the claim");
69	
70	  // === QUOTE: Validation ===
71	  it.todo("unknown item type in quote rejects with error");
72	
73	  // === CLI integration ===
74	  it.todo("CLI reads scenario from stdin and writes results to stdout");
75	  it.todo("CLI exits with non-zero status on error and writes to stderr");
76	});
77

